import React, { Component } from 'react';
import { styled, createTheme, ThemeProvider } from '@mui/material/styles';
import {
  CssBaseline,
  Box,
  AppBar as MuiAppBar,
  Toolbar,
  Typography,
  Button,
  Container,
  Grid,
  Card,
  CardContent,
} from '@mui/material';

const AppBar = styled(MuiAppBar)(({ theme }) => ({
  zIndex: theme.zIndex.drawer + 1,
}));

const defaultTheme = createTheme();

export default class Dashboard extends Component {
  constructor(props) {
    super(props);
    this.state = {
      isNightMode: false,
      selectedTab: 'All',
      projects: {
        All: [
          { title: 'Project 1', description: 'All projects description.', link: 'https://github.com/yourusername/project1' },
          { title: 'Project 2', description: 'All projects description.', link: 'https://github.com/yourusername/project2' },
        ],
        // Add more projects as necessary...
      },
    };
  }

  toggleTheme = () => {
    this.setState((prevState) => ({
      isNightMode: !prevState.isNightMode,
    }));
  };

  render() {
    const { isNightMode, selectedTab, projects } = this.state;

    return (
      <ThemeProvider theme={defaultTheme}>
        <CssBaseline />
        <Box
          sx={{
            display: 'flex',
            flexDirection: 'column',
            height: '100vh',
            backgroundColor: isNightMode ? '#333' : '#fff',
            color: isNightMode ? '#fff' : '#000',
            padding: 2,
          }}
        >
          <AppBar position="absolute">
            <Toolbar component="nav" variant="dense" sx={{ justifyContent: 'space-between', overflowX: 'auto' }}>
              <Typography variant="h6" sx={{ fontWeight: 'bold' }}>My Portfolio</Typography>
              <Button onClick={this.toggleTheme} variant="contained" color="primary">
                {isNightMode ? 'Switch to Day Mode' : 'Switch to Night Mode'}
              </Button>
            </Toolbar>
          </AppBar>

          {/* Hero Section */}
          <Box
            sx={{
              backgroundImage: 'url(https://anur-react.wpocean.com/static/media/right-img.24b30f13.png)',
              backgroundSize: 'cover',
              backgroundPosition: 'center',
              height: '60vh',
              display: 'flex',
              justifyContent: 'center',
              alignItems: 'center',
              color: 'white',
              textAlign: 'center',
            }}
          >
         <section
      style={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        height: '60vh',
        background: '#f0f0f0',
      }}
    >
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          width: '100%',
        }}
      >
        <div
          style={{
            display: 'flex',
            flex: 1,
            justifyContent: 'center',
          }}
        >
          <div
            style={{
              maxWidth: '50%',
              paddingRight: '20px',
            }}
          >
            <div style={{ textAlign: 'left' }}>
              <div>
                <h2
                  style={{
                    fontSize: '48px',
                    fontWeight: 'bold',
                    color: '#333',
                    marginBottom: '20px',
                  }}
                >
                  <span style={{ color: '#3498db' }}>Find</span>
                  <span style={{ color: '#e74c3c' }}>Think</span>
                  <span style={{ color: '#2ecc71' }}>Solve</span>
                </h2>
              </div>
              <div>
                <a
                  href="/about"
                  style={{
                    padding: '10px 20px',
                    backgroundColor: '#3498db',
                    color: '#fff',
                    textDecoration: 'none',
                    borderRadius: '5px',
                    fontSize: '16px',
                  }}
                >
                  View Showcase
                </a>
              </div>
            </div>
          </div>
        </div>
        <div
          style={{
            position: 'relative',
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            maxWidth: '50%',
          }}
        >
          <div
            style={{
              width: '100%',
              display: 'flex',
              justifyContent: 'center',
            }}
          >
            <img
              src="/static/media/right-img.24b30f13.png"
              alt="Right Image"
              style={{
                maxWidth: '100%',
                height: 'auto',
              }}
            />
          </div>
          <div
            style={{
              position: 'absolute',
              width: '150px',
              height: '150px',
              backgroundColor: '#e74c3c',
              borderRadius: '50%',
              top: '10%',
              left: '10%',
            }}
          ></div>
          <div
            style={{
              position: 'absolute',
              width: '100px',
              height: '100px',
              backgroundColor: '#3498db',
              borderRadius: '50%',
              top: '30%',
              right: '20%',
            }}
          ></div>
          <div
            style={{
              position: 'absolute',
              width: '120px',
              height: '120px',
              backgroundColor: '#2ecc71',
              borderRadius: '50%',
              top: '50%',
              left: '15%',
            }}
          ></div>
          <div
            style={{
              position: 'absolute',
              width: '130px',
              height: '130px',
              backgroundColor: '#f39c12',
              borderRadius: '50%',
              bottom: '10%',
              right: '15%',
            }}
          ></div>
        </div>
      </div>
      <div
        style={{
          position: 'absolute',
          bottom: '20px',
          left: '50%',
          transform: 'translateX(-50%)',
        }}
      >
        <ul
          style={{
            listStyle: 'none',
            padding: 0,
            display: 'flex',
            gap: '20px',
            justifyContent: 'center',
          }}
        >
          <li>
            <a
              href="/"
              style={{
                color: '#3498db',
                textDecoration: 'none',
              }}
            >
              Facebook
            </a>
          </li>
          <li>
            <a
              href="/"
              style={{
                color: '#3498db',
                textDecoration: 'none',
              }}
            >
              Twitter
            </a>
          </li>
          <li>
            <a
              href="/"
              style={{
                color: '#3498db',
                textDecoration: 'none',
              }}
            >
              Instagram
            </a>
          </li>
        </ul>
      </div>
    </section>
          </Box>

          {/* Project Section */}
          <Container id="projects" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
            <Typography variant="h4" gutterBottom>
              Projects
            </Typography>

            <Grid container spacing={2}>
              {projects[selectedTab].map((project, index) => (
                <Grid item xs={12} sm={6} md={4} key={index}>
                  <Card sx={{ boxShadow: 3, '&:hover': { boxShadow: 6 } }}>
                    <CardContent>
                      <Typography variant="h5">{project.title}</Typography>
                      <Typography variant="body2">{project.description}</Typography>
                      <Button href={project.link} target="_blank" variant="contained" color="primary" sx={{ mt: 2 }}>
                        View Project
                      </Button>
                    </CardContent>
                  </Card>
                </Grid>
              ))}
            </Grid>
          </Container>

        </Box>
      </ThemeProvider>
    );
  }
}
